    atividade0: Array(12).fill().map(() => new Set()),
    atividade1: Array(12).fill().map(() => new Set())
};

// Processa os dados para contar as atividades por mês (apenas um por dia)
dados.forEach(item => {
    if (item.timestamp && typeof item.timestamp === "string") {
        try {
            // Extrai o mês e o dia a partir do campo 'timestamp' (formato YYYY-MM-DD HH:MM:SS ou YYYY/MM/DD)
            let partesData = item.timestamp.split(" ")[0].split("-");
            let mes = parseInt(partesData[1], 10) - 1; // Converte o mês (1-12) para índice (0-11)
            let dia = partesData[2]; // Extrai o dia

            // Garante que o campo 'atividade' está presente e válido
            if (mes >= 0 && mes < 12 && item.atividade !== undefined) {
                if (item.atividade === 0) {
                    if (!diasProcessados.atividade0[mes].has(dia)) {
                        atividade0[mes]++;
                        diasProcessados.atividade0[mes].add(dia); // Marca o dia como processado
                    }
                } else if (item.atividade === 1) {
                    if (!diasProcessados.atividade1[mes].has(dia)) {
                        atividade1[mes]++;
                        diasProcessados.atividade1[mes].add(dia); // Marca o dia como processado
                    }
                }
            } else {
                node.warn("Mês ou atividade inválidos no item: " + JSON.stringify(item));
            }
        } catch (err) {
            node.warn("Erro ao processar o timestamp: " + item.timestamp + " - Erro: " + err.message);
        }
    } else {
        node.warn("Timestamp ausente ou inválido no item: " + JSON.stringify(item));
    }
});

