// Função para calcular a diferença entre dois timestamps em minutos
function calcularDuracao(timestampInicio, timestampFim) {
    const inicio = new Date(timestampInicio);
    const fim = new Date(timestampFim);

    // Verificar se as datas são válidas
    if (isNaN(inicio.getTime()) || isNaN(fim.getTime())) {
        node.error(`Erro: Datas inválidas. Inicio=${timestampInicio}, Fim=${timestampFim}`);
        return 0; // Retorna 0 para durações inválidas
    }

    // Calcular a diferença em minutos
    return Math.abs((fim.getTime() - inicio.getTime()) / 60000);
}

