// Function to get the week number of a given date
function getWeekNumber(date) {
    let d = new Date(date);
    d.setHours(0, 0, 0, 0);
    d.setDate(d.getDate() + 3 - (d.getDay() + 6) % 7);
    let week1 = new Date(d.getFullYear(), 0, 4);
    return Math.ceil(((d - week1) / 86400000 + 1) / 7);
}

